from pathlib import Path
import re, collections
refs=collections.defaultdict(list)
for p in Path('.gsd').rglob('*.md'):
    if '.gsd/exec' in str(p): continue
    txt=p.read_text(encoding='utf-8', errors='replace')
    for m in re.finditer(r'\bR\d{3}\b', txt):
        rid=m.group(0)
        line=txt.count('\n',0,m.start())+1
        if len(refs[rid])<8:
            # line snippet
            l=txt.splitlines()[line-1].strip()
            if len(l)>180: l=l[:180]+'...'
            refs[rid].append(f'{p}:{line}: {l}')
for rid in [f'R{i:03d}' for i in range(1,55)]:
    print(rid, 'refs', len(refs.get(rid,[])))
    for snip in refs.get(rid,[])[:5]: print(' ',snip)
PY"}

